import { Request, Response } from 'express';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import { UserRepository } from '../repositories/UserRepository';
import { SessionManager } from '../services/SessionManager';
import { RateLimiter } from '../middleware/RateLimiter';
import { Logger } from '../utils/Logger';

const JWT_SECRET = process.env.JWT_SECRET || 'default-secret-change-me';
const JWT_EXPIRY = '24h';
const MAX_LOGIN_ATTEMPTS = 5;
const LOCKOUT_DURATION_MS = 15 * 60 * 1000;

export async function handleLogin(req: Request, res: Response): Promise<void> {
  const { email, password } = req.body;

  if (!email || !password) {
    return res.status(400).json({ error: 'Email and password are required' });
  }

  const rateLimitResult = await RateLimiter.check(email);
  if (rateLimitResult.locked) {
    return res.status(429).json({ error: 'Too many login attempts. Try again later.' });
  }

  try {
    const user = await UserRepository.findByEmail(email);
    if (!user) {
      await RateLimiter.recordFailure(email);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const isValid = await bcrypt.compare(password, user.passwordHash);
    if (!isValid) {
      await RateLimiter.recordFailure(email);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    await RateLimiter.reset(email);
    const token = jwt.sign({ userId: user.id, email: user.email }, JWT_SECRET, { expiresIn: JWT_EXPIRY });
    await SessionManager.create(user.id, token);

    Logger.info('auth:login', { userId: user.id, email: user.email });
    return res.json({ token, user: { id: user.id, email: user.email, name: user.name } });
  } catch (error) {
    Logger.error('auth:login', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
}
