import { Redis } from 'ioredis';
import { Logger } from '../utils/Logger';

const SESSION_TTL = 86400;
const SESSION_PREFIX = 'session:';

export class SessionManager {
  private static redis: Redis;

  static async initialize(): Promise<void> {
    SessionManager.redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');
    Logger.info('session:initialized', { status: 'connected' });
  }

  static async create(userId: string, token: string): Promise<void> {
    const key = `${SESSION_PREFIX}${token}`;
    await SessionManager.redis.setex(key, SESSION_TTL, JSON.stringify({ userId, createdAt: Date.now() }));
    Logger.info('session:created', { userId });
  }

  static async validate(token: string): Promise<{ userId: string } | null> {
    const key = `${SESSION_PREFIX}${token}`;
    const data = await SessionManager.redis.get(key);
    if (!data) return null;
    return JSON.parse(data);
  }

  static async destroy(token: string): Promise<void> {
    const key = `${SESSION_PREFIX}${token}`;
    await SessionManager.redis.del(key);
    Logger.info('session:destroyed', { token: token.substring(0, 8) + '...' });
  }
}
