import { Redis } from 'ioredis';

const MAX_ATTEMPTS = 5;
const WINDOW_MS = 15 * 60 * 1000;

export class RateLimiter {
  private static redis: Redis;
  private static attempts = new Map<string, { count: number; expiresAt: number }>();

  static async check(key: string): Promise<{ locked: boolean; remaining: number }> {
    const now = Date.now();
    const entry = RateLimiter.attempts.get(key);
    if (!entry || entry.expiresAt < now) {
      return { locked: false, remaining: MAX_ATTEMPTS };
    }
    return { locked: entry.count >= MAX_ATTEMPTS, remaining: MAX_ATTEMPTS - entry.count };
  }

  static async recordFailure(key: string): Promise<void> {
    const now = Date.now();
    const entry = RateLimiter.attempts.get(key) || { count: 0, expiresAt: now + WINDOW_MS };
    entry.count++;
    RateLimiter.attempts.set(key, entry);
  }

  static async reset(key: string): Promise<void> {
    RateLimiter.attempts.delete(key);
  }
}
